text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 smoke test가 통과할 경우 금요일 15:00 KST로 한다.",
        "condition": "smoke test 통과"
      },
      {
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인한다. 계약 자체가 잘못된 경우에만 script를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "proposed_by": "Hara",
        "outcome": "rejected"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposed_by": "Seoyeon",
        "status": "internal stretch goal only",
        "note": "Doyun이 smoke test 선통과 필요성을 이유로 반대했으며, 최종 공개 릴리스 목표로 확정되지 않았다."
      },
      {
        "goal": "README 설치 절차를 목요일까지 가능하면 검토한다.",
        "status": "not confirmed as assigned action",
        "note": "소유자가 지정되지 않았다."
      }
    ],
    "non_decisions": [
      "수요일 릴리스는 최종 결정이 아니다.",
      "README 설치 절차 검토는 필요성이 언급되었지만 소유자가 배정되지 않았다.",
      "최종 릴리스 승인 권한자는 정해지지 않았다.",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정되지 않았다."
    ],
    "risks": [
      {
        "risk": "잘못된 tarball path가 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래된 경우 release notes가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 failure triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 generated tarball path를 확인한다.",
      "due": null,
      "status": "confirmed_without_exact_deadline",
      "source_certainty": "explicit"
    },
    {
      "owner": null,
      "task": "README install steps를 목요일까지 가능하면 검토한다.",
      "due": "목요일 if possible",
      "status": "mentioned_without_owner",
      "source_certainty": "explicit"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 smoke test 결과가 금요일 10:00 KST까지 공유되었는지 확인한다.",
      "Doyun의 failure triage note가 action_items.md에 금요일 12:00 KST까지 작성되었는지 확인한다.",
      "smoke 결과 게시 후 Hara가 generated tarball path를 확인했는지 확인한다.",
      "README install steps 검토 소유자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요성",
      "지정되지 않은 owner",
      "정해지지 않은 deadline"
    ]
  },
  "non_invention_rules": {
    "customer": "언급된 고객 또는 외부 파트너가 없으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "owner": "명시적으로 배정되지 않은 작업에는 owner를 null로 둔다.",
    "deadline": "정확한 마감이 없는 항목에는 due를 null 또는 원문 조건으로만 표시한다."
  }
}
